const rawValues = $json.values || [];
const meta = $('Obter Metadados').first().json;
const sheet = meta.sheets.find(s => s.properties.title === 'PROGRAMAÇÃO');
const sheetId = sheet ? sheet.properties.sheetId : 0;

if (rawValues.length < 2) return [{ json: { error: 'Sem dados suficientes' } }];

const row1 = rawValues[0] || [];
const row2 = rawValues[1] || [];
const romaneios = [];

// Lógica igual ao Python: procura na linha 2 por algo que comece com "RM"
for (let c = 2; c < row2.length; c += 2) {
  const name = String(row2[c] || '').trim();
  if (name.toUpperCase().startsWith('RM')) {
    const dateStr = row1[c] || '';
    let parsedDate = null;

    if (dateStr) {
      const p = String(dateStr).match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
      if (p) parsedDate = new Date(parseInt(p[3]), parseInt(p[2])-1, parseInt(p[1]));
      else {
        const s = Number(dateStr);
        if (s > 40000 && s < 60000) parsedDate = new Date((s-25569)*86400000);
      }
    }

    const items = {};
    for (let r = 2; r < rawValues.length; r++) {
      const val = rawValues[r][c];
      if (val !== undefined && val !== '' && val !== null) {
        const num = Number(val);
        if (!isNaN(num) && num !== 0) items[r] = num;
      }
    }
    romaneios.push({ date: parsedDate, name, items });
  }
}

if (romaneios.length === 0) return [{ json: { error: 'Nenhum RM encontrado' } }];

const sorted = [
  ...romaneios.filter(r => r.date).sort((a,b) => a.date - b.date),
  ...romaneios.filter(r => !r.date)
];

const totalRows = rawValues.length;
const totalCols = sorted.length * 2;

function colLetter(n) { let r=''; while(n>0){n--;r=String.fromCharCode(65+n%26)+r;n=Math.floor(n/26);} return r; }

const grid = [];
for (let r = 0; r < totalRows; r++) grid.push(new Array(totalCols).fill(''));

for (let i = 0; i < sorted.length; i++) {
  const rm = sorted[i], t = i*2;
  if (rm.date) grid[0][t] = `${String(rm.date.getDate()).padStart(2,'0')}/${String(rm.date.getMonth()+1).padStart(2,'0')}/${rm.date.getFullYear()}`;
  grid[1][t] = rm.name;
  grid[1][t+1] = 'ESTOQUE INT';
  const prev = t===0 ? 'B' : colLetter(3+t-1), curr = colLetter(3+t);
  for (let r=2; r < totalRows; r++) {
    if (rm.items[r] !== undefined) grid[r][t] = rm.items[r];
    grid[r][t+1] = `=${prev}${r+1}-${curr}${r+1}`;
  }
}

return [{
  json: {
    sheetId,
    writeRange: 'PROGRAMAÇÃO!C1:' + colLetter(2 + totalCols) + totalRows,
    clearRange: 'PROGRAMAÇÃO!C1:DZ' + totalRows,
    values: grid,
    totalRomaneios: sorted.length,
    totalRows
  }
}];

const input = $('Processar').first().json;
const n = input.totalRomaneios, rows = input.totalRows, sid = input.sheetId;
const G={red:0,green:1,blue:0}, LG={red:0.85,green:0.92,blue:0.83}, BL={red:0.56,green:0.67,blue:0.86}, BK={red:0,green:0,blue:0}, RD={red:1,green:0,blue:0};
const rq = [];

// Resetar formatação de fundo e alinhamento do bloco C:DZ
rq.push({
  repeatCell: {
    range: { sheetId: sid, startRowIndex: 0, endRowIndex: rows, startColumnIndex: 2, endColumnIndex: 128 },
    cell: { userEnteredFormat: { backgroundColor: { red: 1, green: 1, blue: 1 }, textFormat: { foregroundColor: { red: 0, green: 0, blue: 0 } }, horizontalAlignment: 'CENTER' } },
    fields: 'userEnteredFormat(backgroundColor,textFormat,horizontalAlignment)'
  }
});

for(let i=0;i<n;i++){
  const c=2+(i*2), hd = input.values[0][i*2] && input.values[0][i*2] !== '';
  // Header Data
  rq.push({repeatCell:{range:{sheetId:sid,startRowIndex:0,endRowIndex:1,startColumnIndex:c,endColumnIndex:c+1},cell:{userEnteredFormat:{numberFormat:{type:'DATE',pattern:'dd/mm/yyyy'},backgroundColor:hd?G:LG,textFormat:{bold:true,fontSize:11},horizontalAlignment:'CENTER'}},fields:'userEnteredFormat(numberFormat,backgroundColor,textFormat,horizontalAlignment)'}});
  // Header ESTOQUE INT (linha 1)
  rq.push({repeatCell:{range:{sheetId:sid,startRowIndex:0,endRowIndex:1,startColumnIndex:c+1,endColumnIndex:c+2},cell:{userEnteredFormat:{backgroundColor:LG}},fields:'userEnteredFormat(backgroundColor)'}});
  // Header Nome RM (linha 2)
  rq.push({repeatCell:{range:{sheetId:sid,startRowIndex:1,endRowIndex:2,startColumnIndex:c,endColumnIndex:c+1},cell:{userEnteredFormat:{backgroundColor:BL,textFormat:{bold:true,fontSize:10},horizontalAlignment:'CENTER',wrapStrategy:'WRAP'}},fields:'userEnteredFormat(backgroundColor,textFormat,horizontalAlignment,wrapStrategy)'}});
  // Header ESTOQUE INT (linha 2)
  rq.push({repeatCell:{range:{sheetId:sid,startRowIndex:1,endRowIndex:2,startColumnIndex:c+1,endColumnIndex:c+2},cell:{userEnteredFormat:{backgroundColor:LG,textFormat:{bold:true,fontSize:10},horizontalAlignment:'CENTER'}},fields:'userEnteredFormat(backgroundColor,textFormat,horizontalAlignment)'}});
  // Dados ESTOQUE INT (linhas 3+)
  rq.push({repeatCell:{range:{sheetId:sid,startRowIndex:2,endRowIndex:rows,startColumnIndex:c+1,endColumnIndex:c+2},cell:{userEnteredFormat:{backgroundColor:LG,textFormat:{bold:true}}},fields:'userEnteredFormat(backgroundColor,textFormat)'}});
}

// Condicional Negativo Vermelho
rq.push({
  addConditionalFormatRule: {
    rule: {
      ranges: [{ sheetId: sid, startRowIndex: 2, endRowIndex: rows, startColumnIndex: 2, endColumnIndex: 2 + n * 2 }],
      booleanRule: {
        condition: { type: 'NUMBER_LESS', values: [{ userEnteredValue: '0' }] },
        format: { backgroundColor: RD }
      }
    },
    index: 0
  }
});

return [{json:{requests:rq}}];
